import React, { useEffect, useState } from 'react';
import Card from './Card'; 
import '../style/CardWithData.css';
import { useFilterContext } from '../ContextApi/FilterApi';

const CardWithData = () => {
    const [data, setData] = useState([]);
    const context = useFilterContext();

    useEffect(() => {
        const fetchData = async () => {
            if(!context.category)
            {
                const response =await fetch("http://localhost:8000/Menu");
                setData(response);
            }
            try {
                const fixed = "http://localhost:8000/Menu";
                const response = await fetch(`${fixed}?filter=${context.category}`);
                const result = await response.json();
                console.log("Fetched data:", result);
                setData(Array.isArray(result) ? result : []);
            } catch (error) {
                console.error("Error fetching data: ", error);
            }
        };

        fetchData();
    }, [context.category]);

    return (
        <div className="cards-container">
            {data.length === 0 ? (
                <p>Loading data...</p>
            ) : (
                data.map((item) => (
                    <Card
                        // key={item.id} 
                        // imgSrc={item.imgSrc} // Include if imgSrc is part of data
                        name={item.item}
                        price={item.price}
                        // description={item.description} // Include if description is part of data
                    />
                ))
            )}
        </div>
    );
};

export default CardWithData;
